/**
 * Resolve a chain identifier to a numeric EVM chain ID.
 * Accepts a known chain name (e.g. "base") or a numeric string / number.
 */
export function resolveChainId(chain: string | number): number {
  if (typeof chain === "number") return chain
  const asNum = Number(chain)
  if (!Number.isNaN(asNum) && Number.isInteger(asNum)) return asNum
  const id = CHAIN_IDS[chain]
  if (id === undefined) {
    throw new Error(
      `Unknown chain "${chain}". Pass a numeric chain ID or use a known name: ${Object.keys(CHAIN_IDS).join(", ")}`,
    )
  }
  return id
}
